import{_ as i}from"./plugin-vue_export-helper-c27b6911.js";import{o as e,c as g,e as t}from"./app-47a81c5c.js";const n="/assets/image-20240506104829591-e9e566bb.png",r="/assets/image-20240506105940150-1baa289e.png",s="/assets/image-20240506110235081-b39be6d6.png",a="/assets/image-20240506141157665-7029a318.png",p="/assets/image-20240506111407156-688e97d6.png",c="/assets/image-20240506141526931-1cdef42c.png",o="/assets/image-20240506141602355-746d5adc.png",d="/assets/image-20240506141625985-5e981df8.png",f="/assets/image-20240506141836460-2e1897d6.png",m="/assets/image-20240506112928799-3512dc1c.png",h="/assets/image-20240506142153735-b9a91d3d.png",l="/assets/image-20240506142221430-3435b50e.png",u="/assets/image-20240506142551621-2f4bd36c.png",_="/assets/image-20240506142657732-4d3203a3.png",b="/assets/image-20240506143102283-cfcaf0c2.png",x="/assets/image-20240506143342879-7ed0865e.png",y="/assets/image-20240506143356784-8f2e7249.png",z="/assets/image-20240506143836261-0528a155.png",v="/assets/image-20240502144919070-300ff4d3.png",A="/assets/image-20240502144950226-da10f8bc.png",E="/assets/image-20240502145105896-6dde0dec.png",M="/assets/image-20240502145143945-fe163cce.png",T="/assets/image-20240502145227976-085ade2f.png",k="/assets/image-20240502145255442-e43ade85.png",B="/assets/image-20240502145330903-dccc70b1.png",N="/assets/image-20240502145423870-17cad6cf.png",w="/assets/image-20240502145515183-4b126e98.png",D="/assets/image-20240502145620696-aeb2a5cb.png",S="/assets/image-20240502145811361-b6333888.png",V="/assets/image-20240502145847014-dea8d26d.png",X="/assets/image-20240502150037933-c92c8e8f.png",j="/assets/image-20240502150148562-ae4d3331.png",q="/assets/image-20240502150343878-be9828ae.png",C="/assets/image-20240502150505314-4f6046b9.png",F="/assets/image-20240502150712476-3b6a9395.png",G="/assets/image-20240502150758539-078eceb4.png",H="/assets/image-20240502150827692-774f7218.png",I="/assets/image-20240502150918040-729d479a.png",J="/assets/image-20240502151022073-aea2b61b.png",K="/assets/image-20240502151100321-a57e3040.png",L={},O=t('<h1 id="mat博主教程" tabindex="-1"><a class="header-anchor" href="#mat博主教程" aria-hidden="true">#</a> MAT博主教程</h1><h2 id="交易系统" tabindex="-1"><a class="header-anchor" href="#交易系统" aria-hidden="true">#</a> 交易系统</h2><p>今天我将会教你们手把手的建立属于你自己的交易策略系统，成为一个少数的可以长期盈利的交易者。</p><figure><img src="'+n+'" alt="image-20240506104829591" tabindex="0" loading="lazy"><figcaption>image-20240506104829591</figcaption></figure><p>让我们开始进入主题吧。首先我们来看。为什么一个交易者会长期在亏损钱呢？其实最根本的一个问题就是他们没有一个完整的交易系统。在没有一个完整的交易系统进场时，你不知道股价现在是在上升趋势还是下降趋势，不知道该什么时候进场，什么时候应该止损和什么时候应该止盈走人。所以这样就好比你在跟人家比大小。买进股票后就双手合十，祈祷股票会上升。</p><p>我们来举个例子，这时候当你买进的股票已经涨了很多时，人性的贪念这时候就会体现了。你就会想着股票应该还会再涨，然后就紧握着你的票，继续等待股价的暴涨，没想到最后股票暴跌，这时候你就开始慌了，所以最后当股价回到你的成本价的时候，你会急匆匆的把股票给卖了。你忙活了这么久，到头来什么都没赚到。</p><figure><img src="'+r+'" alt="image-20240506105940150" tabindex="0" loading="lazy"><figcaption>image-20240506105940150</figcaption></figure><p>但是你有错吗？并没有。因为这个是人性。当你赚的多时，你就会想着赚更多。当你亏时你就会想着好吧，股价回到我的成本，我就把股票卖了。因为人总是会厌恶损失。所以总结来说。在没有一个完整的交易体系进场时，你会一直被你的情绪牵着鼻子走。然后你会对你这个交易很没有自信。你不懂几时要买几时要买？所以一个持续盈利的交易者会建立一个属于他自己的交易体系，这样可以帮助你不被自身的情绪影响你的交易。</p><figure><img src="'+s+'" alt="image-20240506110235081" tabindex="0" loading="lazy"><figcaption>image-20240506110235081</figcaption></figure><p>当你建立了交易系统后，我们只需要做的只是跟随，跟着指示几时进场，为什么可以进场？止损在哪里和止盈在哪里？这样你就会对你的交易开始有自信了。所以当你的股票在跌时，你也不会感到恐慌，因为你知道你的止损点在哪里，只要股价触碰到。止损点就坚决离场。或者是股价暴涨，你也不会慌张。只要股价触碰到你的止盈，就直接逃离离场。</p><h3 id="第一元素-计划" tabindex="-1"><a class="header-anchor" href="#第一元素-计划" aria-hidden="true">#</a> 第一元素：计划</h3><p>现在让我们进入交易策略的第一元素，那就是计划。</p><figure><img src="'+a+'" alt="image-20240506141157665" tabindex="0" loading="lazy"><figcaption>image-20240506141157665</figcaption></figure><p>在每次进行交易之前，我们都要做好计划才入场。那计划又可以分为5个要点：</p><p>首先我们要确认股价趋势，为什么我们要确认趋势呢？因为我们要顺着趋势交易。我们需要跟趋势做朋友。</p><figure><img src="'+p+'" alt="image-20240506111407156" tabindex="0" loading="lazy"><figcaption>image-20240506111407156</figcaption></figure><p>那什么是趋势呢？</p><p>趋势可以分为三种，第一是上升趋势。当现在是股价处在上涨趋势时。我们就要顺着趋势来买进。</p><p>第二是横盘趋势，当股价处在横盘趋势时，我们可以做的是观望，不要进场。为什么呢？因为你不知道股价会横盘多久？有可能横盘一个月，也有可能横盘一年。如果你在股价横盘中进场。往往你就会被套住。有可能你等了几个星期股价才涨那么一点点。那为什么你不要等股价转换成上升行情你才进场做多呢？这样是不是更省时间和更高胜率呢？</p><figure><img src="'+c+'" alt="image-20240506141526931" tabindex="0" loading="lazy"><figcaption>image-20240506141526931</figcaption></figure><figure><img src="'+o+'" alt="image-20240506141602355" tabindex="0" loading="lazy"><figcaption>image-20240506141602355</figcaption></figure><p>第三，那就是下跌趋势，在下跌趋势中。千万不要买进。不要跟趋势唱反调。不然你往往都会止损离场。</p><figure><img src="'+d+'" alt="image-20240506141625985" tabindex="0" loading="lazy"><figcaption>image-20240506141625985</figcaption></figure><p>这时候一定有很多人会问我，之前在上涨趋势中买进。但是股价就一直在横盘。有些人的股价甚至还下跌，直接触碰到止损，最后止损离场。他们就说我已经在上涨趋势中买进了，那为什么股价不会升？大家一定会有这个疑惑，对不对？让我在这边详细的解释股票的原理给大家。</p><p>首先股票其实是一个概率的游戏，我们不能确定每次买入的股票都100%会上涨。有时候当你止损卖出股票后。股价却在你卖出后却突然暴增了58%，或者有时候当你买入这支股票后，股价往往会横盘好久，甚至是下跌。所以说股票是一个概率的游戏，我们并不能叫股票涨它就涨。叫股票跌它就跌，我们能做的事只能是做好自己。确认我们每一次在进行交易中都是做着正ev的决定。这样你长久下来一定是会盈利的，那什么是ev呢？让我也解释一下什么是ev给大家听吧。</p><p>Ev全名是expected value。翻译过来就是期望值。简单来说就是在一个长时间的投资过程中，我现在这一个的交易中所做的决定，平均每次会为我带来多少收益。正ev就是说你这个决定在长期的投资里可以赚到钱。负ev就是说你的这个决定以长期来看的话是会亏钱的。让我举一个例子，这样大家会更明白什么是ev。现在我这边有两个箱子。两个箱子都各有5颗球。在a箱子中有三颗红球和两颗白。在b箱子中有三颗白球和两颗红。当你抽中红球时，你会获得1000块。当你抽中白球时，你会输1000块。如果是你的话，你会选a箱子还是b箱子呢？我给大家5秒钟选择。</p><figure><img src="'+f+'" alt="image-20240506141836460" tabindex="0" loading="lazy"><figcaption>image-20240506141836460</figcaption></figure><p>相信大家都会选离箱子吧。那恭喜大家做出了正ev的决定。所以原理是因为一箱子的红球数量多过白球。所以投资交易的原理就是当你在每个交易都做出选择a箱子的决定，这样以长久下来就可以保持盈利了。</p><p>那现在我们用这个例子延伸去投资里。股价不会无端端拉升或者是下跌。股价会上升和下跌，一定是有大量的人和金钱在买进或者是卖出。所以当股价在下跌时，现在大量的人和金钱在卖出。股价大概率是会继续下跌的。所以当你选择在下跌趋势中买进，你就好比选择了b箱子，做了一个负ev的决定。长久下来一定是会亏钱的。当股价在上涨时，也意味着大量的人和金钱在买进。所以这时候当我们顺着大众买进。这样我们好比选择了a箱子。做了一个正ev的决定，这样的话我们长久下来一定是赚钱的。</p><figure><img src="'+m+'" alt="image-20240506112928799" tabindex="0" loading="lazy"><figcaption>image-20240506112928799</figcaption></figure><p>那现在相信大家都知道要顺势交易了。那怎样可以判断趋势呢？其实有很多指标可以让我们判断趋势，例如我们可以用移动平均线，趋势线各种形态，比如下降楔形，三角形，双底，三重底头尖底等等还有很多。</p><p>当我们选择其中一种指标来判断趋势后。我们就要为他设立更仔细的规则。我们需要设立越详细越清楚的规则越好。因为一个完善的交易系统就是要够完善和够清楚。举个例子，我们现在用突破趋势线来买入股票。</p><h4 id="判断趋势" tabindex="-1"><a class="header-anchor" href="#判断趋势" aria-hidden="true">#</a> 判断趋势</h4><p>第一步，我们来判断趋势。因为股价突破了下降趋势线，所以股价现在是在上升趋势，然后我们等股价回调，那股价需要回调到什么具体位置我们才进场。</p><figure><img src="'+h+'" alt="image-20240506142153735" tabindex="0" loading="lazy"><figcaption>image-20240506142153735</figcaption></figure><h4 id="设置条件" tabindex="-1"><a class="header-anchor" href="#设置条件" aria-hidden="true">#</a> 设置条件</h4><p>第二步，我们要为这个交易系统设立条件。现在我们用斐波纳奇回测。股价必须回调至0.5<sub>0.618的斐波那契价位。因为0.5</sub>0.618是斐波那契的黄金价位。所以当股价回调跌破0.618或者是还没回调到0.5就上涨了，我们都不会进行交易。所以这样就很清楚了，我们要把交易系统设置的越清楚越好。清楚到你请别人来使用你这个交易系统，它也可以很清楚地跟着交易系统的指示进行交易。</p><figure><img src="'+l+'" alt="image-20240506142221430" tabindex="0" loading="lazy"><figcaption>image-20240506142221430</figcaption></figure><h4 id="入场点" tabindex="-1"><a class="header-anchor" href="#入场点" aria-hidden="true">#</a> 入场点</h4><p>第三步入场点，因为真正意义上的上涨趋势是形成higher high，然后回调形成higher low，最后突破前期高点形成higher high。所以我们把入场点设置为当股价突破前期高点时我们就进场。这样我们就有双重确认说这支股票现在是在上涨的趋势，这双重确认就是股价突破，下降趋势线和股价突破前期高点。</p><figure><img src="'+u+'" alt="image-20240506142551621" tabindex="0" loading="lazy"><figcaption>image-20240506142551621</figcaption></figure><h4 id="止损点" tabindex="-1"><a class="header-anchor" href="#止损点" aria-hidden="true">#</a> 止损点</h4><p>第四步，现在我们要来设置止损点。为什么要设置止损点呢？就好像刚刚我所说的投资是一个概率的游戏，所以当市场往我们预期的反方向走时，我们就要认输离场，安心等待下一次入场的机会。除此之外，当股价在下跌时，你也不会感到慌张。因为你设置了止损点，只要股价抵达止损点。你就马上止损离场。我们可以使用atr这个技术指标。他的全名是average to range。因为每一只股票的股价波动都不一样，有些股票的波动很大。有些股票的波动很小。所以这个技术指标可以让你知道这一支股票股价的波动是多少？现在我们设置两个atr以下，为我们的止损点。</p><figure><img src="'+_+'" alt="image-20240506142657732" tabindex="0" loading="lazy"><figcaption>image-20240506142657732</figcaption></figure><h4 id="止盈点" tabindex="-1"><a class="header-anchor" href="#止盈点" aria-hidden="true">#</a> 止盈点</h4><p>第五步，我们来设置止盈点。盈亏比就以1.5:1。止盈点的比例一定要设比止损点的比例来的大。不管你设置1.5倍、两倍、三倍这些通通都可以，只要盈亏比正确，长期下来你是可以获利的。现在在我们设置完这些之后，一个完整的计划就诞生了。</p><p>让我们来重新回顾一下。首先我会等股价突破趋势线，当股价突破趋势线，我们要怎样呢？所以来到第2步突破趋势线后，我们用斐波那契回测等股价回调。那回调到多少我们才会入场呢？所以我们刚刚已经设置过了，股价一定要回调到0.5和0.618这个斐波纳级黄金区域之间。如果股价还没到这个区域就涨或者是跌破了这个区域。我们都不会去参与这个交易。然后现在股价回调至我们的黄金区域了。那我们的入场信号是什么呢？在这边我设置了当股价突破前期高点我们就进场做多。如果股价往下走，我们要怎么办？所以我们设置了止损点。那如果股价往上走呢？所以我们也设置了止盈点。你可以发现我们一整套的计划每一个步骤都是很详细，无论股价往哪一个方向走，我们都有对策。所以这就是一个完整的交易计划。</p><figure><img src="'+b+'" alt="image-20240506143102283" tabindex="0" loading="lazy"><figcaption>image-20240506143102283</figcaption></figure><h3 id="第二元素-资金风险管控" tabindex="-1"><a class="header-anchor" href="#第二元素-资金风险管控" aria-hidden="true">#</a> 第二元素：资金风险管控</h3><figure><img src="'+a+'" alt="image-20240506141157665" tabindex="0" loading="lazy"><figcaption>image-20240506141157665</figcaption></figure><p>在我们制定了交易计划后。我们就可以往交易系统的第2步前进，那就是资金的风险管控。什么是资金风险管控呢？顾名思义，那就是你对你的资金风险的控制能力。比如说在你每次交易中，你可以承担的亏损的单笔交易是多少百分比或者是你最大愿意以多少百分比的总资金来进行一次交易？</p><p>为什么我们要对资金的风险进行管控呢？</p><h4 id="避免我们输掉所有的资金" tabindex="-1"><a class="header-anchor" href="#避免我们输掉所有的资金" aria-hidden="true">#</a> 避免我们输掉所有的资金</h4><p>第一可以避免我们输掉所有的资金，止损是我们可以控制的，所以只要我们严格管控我们的止损和止盈。我们一定可以长期的在市场上盈利。</p><p>我们来举个例子。 a先生和b先生。他们两个人各有100块。今天他们同时进行了同一个交易。最后股价暴跌，他们两个。都止损离场。那问题来了，为什么a先生输了钱后是笑着呢？反观b先生输了钱是哭着的。那是因为a先生有做资金的风险管控。他把止损设置在10%，所以最后他只输10块钱。b先生呢，因为他没有对资金做风险管控，当股价暴跌后，他才急匆匆的止损离场。最后损失了55%，仅剩下50块。</p><figure><img src="'+x+'" alt="image-20240506143342879" tabindex="0" loading="lazy"><figcaption>image-20240506143342879</figcaption></figure><p>接下来让我们看一下这个图表。a先生只需要赚11.11%就可以回本了。但是b先生需要赚100%才可以回本。所以总结来说，在投资市场里你首要做的其实并不是盈利，而是保存资金，因为当你没有了资金，何来盈利呢？</p><figure><img src="'+y+'" alt="image-20240506143356784" tabindex="0" loading="lazy"><figcaption>image-20240506143356784</figcaption></figure><h4 id="情绪不被市场控制" tabindex="-1"><a class="header-anchor" href="#情绪不被市场控制" aria-hidden="true">#</a> 情绪不被市场控制</h4><p>第二，做好资金风险管控，可以帮助我们的情绪，不会被市场影响。如果我们在单笔交易的资金过大的话。当股交只要稍微的起伏，我们的心情就会跟着被影响。并且我们会随时随刻的查看股价。导致我们的生活受影响。当我们情绪受影响时，我们就很难跟着我们设定的交易系统来交易了。这些种种的因素都源自什么呢？那就是你的资金比例过大。那你就要缩小你放进去的资金比例，并且做好止损和止盈。可能有些人会问那资金比例是多少才最适合呢？当你投入了那笔资金，无论是股价涨或者跌，你都可以做到生活完完全全不被影响，并且做好一件事，那就是交易你的计划，计划你的交易，大家可以谨记这段话，只要做得到这段话所说的东西，相信我，你一定会盈利的。</p><h3 id="第三元素-纪律" tabindex="-1"><a class="header-anchor" href="#第三元素-纪律" aria-hidden="true">#</a> 第三元素：纪律</h3><p>接下来我们来看交易策略系统的最后一项。那就是纪律。其实说白了，纪律这个东西是当你完成了前面两项元素。也就是计划和资金风险管控。你自然而然就会有纪律了。为什么呢？为什么一个人在交易中会有纪律呢？</p><p>首先因为那个人他有足够的信心，那为什么他这么的自信呢？因为它有一个完整的交易系统。他足够的清楚他现在所做的每一件事。每一个步骤都是跟随着它所制定的交易系统。他做到了这段话。交易你的计划，计划你的交易所说的内容。</p><p>第二，他在整个交易过程完全没有情绪。因为他对自己有着风险的管控。他所下的每个单的资金都在他可以承担的范围。所以它不会被市场的波动影响。这样就不会导致因为情绪的问题而产。产生没有纪律的问题和改变自己的交易系统。</p><p>第三他有足够的自信，为什么呢？因为他对他这个交易系统实测和回撤了好多次。他已经完完全全熟悉这个交易系统和了解了交易系统的胜率。所以它对它的交易系统有足够的自信，所以在实际使用之前，我们必须要实测和回撤我们的交易系统。</p><figure><img src="'+z+'" alt="image-20240506143836261" tabindex="0" loading="lazy"><figcaption>image-20240506143836261</figcaption></figure><p>这些就是今天我要分享给你们的一个完整交易策略系统。最后我想说的还是这句话。交易你计划的，并计划已交易的，当你们严格执行你们的计划，并且做好风险管控和有几率长久的持续下去。我相信你们一定可以盈利的。</p><h2 id="支撑线和阻力线" tabindex="-1"><a class="header-anchor" href="#支撑线和阻力线" aria-hidden="true">#</a> 支撑线和阻力线</h2><p>这只影片我将会介绍：</p><p>1、什么是支撑线和阻力线</p><p>2、4个使用支撑与阻力线必须知道的事</p><p>3、使用支撑与阻力线来进场和出场的交易策略</p><p>4、最后我将会分享我如何画支撑与阻力线的技巧与细节。</p><h3 id="什么是阻力线" tabindex="-1"><a class="header-anchor" href="#什么是阻力线" aria-hidden="true">#</a> 什么是阻力线？</h3><p>阻力线是当股价多次突破不了某个价位，那个位置就形成股价的阻力位，在画阻力线时至少连接两个或以上的点方为一个有效的阻力。</p><figure><img src="'+v+'" alt="image-20240502144919070" tabindex="0" loading="lazy"><figcaption>image-20240502144919070</figcaption></figure><h3 id="什么是支撑线" tabindex="-1"><a class="header-anchor" href="#什么是支撑线" aria-hidden="true">#</a> 什么是支撑线？</h3><p>支撑线是当股价多次跌不破某个位置，那个位置就形成一个支撑。一个有效的支撑线是至少连接两个或以上的点。</p><figure><img src="'+A+'" alt="image-20240502144950226" tabindex="0" loading="lazy"><figcaption>image-20240502144950226</figcaption></figure><h3 id="支撑与阻力的知识与细节" tabindex="-1"><a class="header-anchor" href="#支撑与阻力的知识与细节" aria-hidden="true">#</a> 支撑与阻力的知识与细节</h3><h4 id="支撑与阻力线的转化运用" tabindex="-1"><a class="header-anchor" href="#支撑与阻力线的转化运用" aria-hidden="true">#</a> 支撑与阻力线的转化运用</h4><p>当股价突破阻力线时，阻力线将会变成支撑线，当下次市股价回到该位置时就会形成支撑，支撑住股价。</p><figure><img src="'+E+'" alt="image-20240502145105896" tabindex="0" loading="lazy"><figcaption>image-20240502145105896</figcaption></figure><p>反之当股价跌破支撑线时，支撑线将会变成阻力线，当股价再次回到该价位，它将形成有效的阻力。</p><figure><img src="'+M+'" alt="image-20240502145143945" tabindex="0" loading="lazy"><figcaption>image-20240502145143945</figcaption></figure><h4 id="支撑与阻力的强度与有效性" tabindex="-1"><a class="header-anchor" href="#支撑与阻力的强度与有效性" aria-hidden="true">#</a> 支撑与阻力的强度与有效性</h4><p>当一个支撑与阻力线连接越多的点，它的强度以及有效的程度越大。所以举个例子，一个连接了4个点的阻力线，会比连接两个点的阻力线来的有效。</p><figure><img src="'+T+'" alt="image-20240502145227976" tabindex="0" loading="lazy"><figcaption>image-20240502145227976</figcaption></figure><figure><img src="'+k+'" alt="image-20240502145255442" tabindex="0" loading="lazy"><figcaption>image-20240502145255442</figcaption></figure><h4 id="区域对待" tabindex="-1"><a class="header-anchor" href="#区域对待" aria-hidden="true">#</a> 区域对待</h4><p>支撑与阻力并不是单单一条线，我们要把它当做一个区域来对待。所以当股价到达支撑区域或阻力区域就会有所反弹。</p><figure><img src="'+B+'" alt="image-20240502145330903" tabindex="0" loading="lazy"><figcaption>image-20240502145330903</figcaption></figure><figure><img src="'+N+'" alt="image-20240502145423870" tabindex="0" loading="lazy"><figcaption>image-20240502145423870</figcaption></figure><p>当你实际画的时候，是不是觉得很混乱，觉得太多支撑与阻力线了。分不清楚要使用哪一个。</p><figure><img src="'+w+'" alt="image-20240502145515183" tabindex="0" loading="lazy"><figcaption>image-20240502145515183</figcaption></figure><h4 id="不同时间级别的支撑与阻力" tabindex="-1"><a class="header-anchor" href="#不同时间级别的支撑与阻力" aria-hidden="true">#</a> 不同时间级别的支撑与阻力</h4><p>从大时间级别来化，支撑与阻力会比较清晰以及简单。以及大时间级别的支撑与阻力会比小时间级别的支撑与阻力强度与有效度来得大。所以在使用大时间级别的图画支撑与阻力时，你就会很清楚地发现重要的支撑与阻力不会再画几十条支撑与阻力了。</p><figure><img src="'+D+'" alt="image-20240502145620696" tabindex="0" loading="lazy"><figcaption>image-20240502145620696</figcaption></figure><h3 id="进场的策略" tabindex="-1"><a class="header-anchor" href="#进场的策略" aria-hidden="true">#</a> 进场的策略</h3><p>首先进场的策略分别是突破买入法和回调买入，我会分别介绍以及他们的优缺点。</p><h4 id="突破买入法" tabindex="-1"><a class="header-anchor" href="#突破买入法" aria-hidden="true">#</a> 突破买入法</h4><p>突破买入是当股价突破阻力线时，我们可以看作是突破了某个重要的障碍，接下来看涨。</p><figure><img src="'+S+'" alt="image-20240502145811361" tabindex="0" loading="lazy"><figcaption>image-20240502145811361</figcaption></figure><p>所以当股价突破阻力位置时就可以买入，优点是可以及时捉到后面一大波的利润。缺点是如果有假突破，你将会买在高点住在高楼，什么是假突破呢？我之后会做关于假突破的视频来讲解。</p><figure><img src="'+V+'" alt="image-20240502145847014" tabindex="0" loading="lazy"><figcaption>image-20240502145847014</figcaption></figure><h4 id="回调买入法" tabindex="-1"><a class="header-anchor" href="#回调买入法" aria-hidden="true">#</a> 回调买入法</h4><p>回调买入法是当股价突破阻力时，等待股价再次回落，该位置才进行买入。动作优点是比较稳健和安全，缺点是股价没有进行回调，而是直接暴涨，那你将会错失一大波的涨幅，错失机会。</p><figure><img src="'+X+'" alt="image-20240502150037933" tabindex="0" loading="lazy"><figcaption>image-20240502150037933</figcaption></figure><h3 id="离场的策略" tabindex="-1"><a class="header-anchor" href="#离场的策略" aria-hidden="true">#</a> 离场的策略</h3><p>离场的策略是我们可以使用支撑线来设置止损。我们可以把止损点设置在支撑位的下方，所以股价要抵达你的止损点之前必须要挑战了支撑位方才可以触碰到你的止损。</p><figure><img src="'+j+'" alt="image-20240502150148562" tabindex="0" loading="lazy"><figcaption>image-20240502150148562</figcaption></figure><h3 id="画支撑与阻力线的细节与心得" tabindex="-1"><a class="header-anchor" href="#画支撑与阻力线的细节与心得" aria-hidden="true">#</a> 画支撑与阻力线的细节与心得</h3><p>线是要画在实体上还是虚线上？</p><p>我的画法是以触碰到最多点的大前提下，无论是触碰到实体或者是虚线上。首先我会去大时间级别的图来画支撑与阻力，因为我是波段交易者，所以我的大时间级别是周图和月图，日图是我的小时间级别。</p><figure><img src="'+q+'" alt="image-20240502150343878" tabindex="0" loading="lazy"><figcaption>image-20240502150343878</figcaption></figure><p>我通常指绘画靠近现在的股价的支撑与阻力，这样会节省很多时间，之后股价突破或跌破后再画就是了。我的做法是先画了一条线，再把它画成一个区域，然后颜色改成青色，以此区别大时间级别和小时间级别的支撑与阻力。画完月图和周图后，我就会转去日图画股价最近的支撑与阻力。所以这样就很清楚了，以DENX这支股为例子，阻力是0.83，支撑是0.78。</p><figure><img src="'+C+'" alt="image-20240502150505314" tabindex="0" loading="lazy"><figcaption>image-20240502150505314</figcaption></figure><h3 id="完整策略示范" tabindex="-1"><a class="header-anchor" href="#完整策略示范" aria-hidden="true">#</a> 完整策略示范</h3><p>画支撑线，画阻力线</p><figure><img src="'+F+'" alt="image-20240502150712476" tabindex="0" loading="lazy"><figcaption>image-20240502150712476</figcaption></figure><p>在支撑位下方设置止损点，在阻力位设置止盈点</p><figure><img src="'+G+'" alt="image-20240502150758539" tabindex="0" loading="lazy"><figcaption>image-20240502150758539</figcaption></figure><p>等待</p><figure><img src="'+H+'" alt="image-20240502150827692" tabindex="0" loading="lazy"><figcaption>image-20240502150827692</figcaption></figure><p>突破买入</p><figure><img src="'+I+'" alt="image-20240502150918040" tabindex="0" loading="lazy"><figcaption>image-20240502150918040</figcaption></figure><p>在支撑位下方设置止损点</p><figure><img src="'+J+'" alt="image-20240502151022073" tabindex="0" loading="lazy"><figcaption>image-20240502151022073</figcaption></figure><figure><img src="'+K+'" alt="image-20240502151100321" tabindex="0" loading="lazy"><figcaption>image-20240502151100321</figcaption></figure><p>支撑与阻力是技术分析的必学的技巧，但我们并不能单单用支撑与阻力来当作唯一的买点，需配合其他的技术面工具及分析。</p>',130),P=[O];function Q(R,U){return e(),g("div",null,P)}const Z=i(L,[["render",Q],["__file","MTA博主教程.html.vue"]]);export{Z as default};
